INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1153, 189442, 2, 1053, '客家流沙之应古', '我认识的,或者是记忆中的这名老人叫应古。古为音译，指代为雄性，如公牛称为牛古；相对应的雌性称嬷，同样人畜共享，母鸡叫鸡嬷，母猪叫猪嬷，以此类推；女性则如天秀嬷银真嬷等。古与嬷的不同在于，男性的古之前一般只是用名中的最后一字，如福生叫生古、玉应叫应古，而女性则全名加后缀嬷，如应古的老婆叫庸凤嬷，为什么有这个区别，没有人知道；太多的文明已被时光的流沙淹没了。 
<br>
<br>     应古的形象仿佛香港的老明星麦嘉，秃头，精瘦硬朗，蓝色卡叽布的上衣和同样宽大飘荡的抽头裤，走起路来颇为飘然空灵，衣服上总有几块或灰或黑的补丁和他脸皮的酱黑相衬，他的脚有某种皮肤病，象要褪皮的烂蛇，一个个铜钱大的黄褐斑。在86年之前，我们宗族中只有他吃蛇，所以每当有人打死了蛇，想到的就是应古；有人促狭要别人吃脏的或剩的东西时，一般都会抬出应古来反击：我才不是应古呢――死蛇烂蛙都吃。到后来人们都吃蛇，捕蛇赚钱，甚至于把田埂、山岭都挖出无数大洞时，应古已经快死了。 
<br>
<br>     客家人多住土楼，土墙黑瓦，楼挨着楼，象是些上了年纪的人的心事重叠。应古的家是众土楼中的两间破败的矮房，瓦房上也有几张杉树皮的补丁。阴暗，潮湿，木格的窗棂永远是阳光斜斜的窜进来偷窥。他的老伴、儿子、儿媳妇、孙子、孙女就住在隔壁的楼房里，中间有一个两米高的围墙，里侧一扇小木门，墙根下绿浸浸的苔藓和已爬蔓绽花的人参草。小门吱嘎开了，孙子探出头怯怯的叫：大大。应古的沙锣声从矮房的黑暗中忙不迭的传出来，秃头刚出现在视线中时，孙子已被媳妇的手一把拎回去了，铁门叶的上锁清脆声和媳妇假意的说明，令应古的脸埋藏在阴影中。不过，他并不是不快乐的。路人常可听到路坎下应古哼着黄梅小调自饮两角干白，那种闲散的情调会勾起人们的笑意，于是，又有了个教训儿女的好例证：象你这个样子下去，长大了就和应古唱黄梅戏去哦。 
<br>
<br>     当然应古的快乐不止于老白干。青黄不接时，到处是稻子青苗，牛们放野不得，必须人牵着放牧。或是河边芦苇丛，或是山岗上，更多的是青草茂盛的田埂上，一个戴竹笠的人后面跟随一头饥肠�r�r的牛古或牛嬷，在婉约的泥埂上随着牛吃草的节奏行进。应古的黄牛嬷有一个与众不同的特点，即便青油油的禾苗近在鼻前，它也是忠实只啃田埂上的青草。应古便只需躺在不远处的草地上，脸上覆着竹笠唱山歌。他唱的山歌基本上是潮州《三斤狗肉公》的调，开头一句必然是以咏叹语气：喂�健�―后面一字是拖着极长的上扯音，待到听起来一口气行将结束时，蓦然下坠，紧接着唱词逶迤的飞上天空。唱词是完全随意而编的，有时他唱的是自已的身平，说他如何自小从广东被卖到这儿，跟着瘸老汉吃苦多少年，从来娶妻为做饭，如今只身被窝寒……唱词间歇时会有一句极叹谓的“呜――呼”，唱得真切了，便有田坎上铲豆子草的农妇扯着围襟擦拭眼泪，带着哭腔哀求：应古大伯你莫唱了哩。有时应古则是唱得极为随意，简直就是卒不忍听的流水帐：喂�健�―早晨天光六点半，上趟屎缸再煮饭；狗古�由つ宽耥瘢�行来行去磕脚跟……路过的男人们听了，不由的唏一声：那个应古又在发日头神了。应古唱得得意时，头藏在竹笠中，二郎腿一晃一晃的，将腿上的蛇皮斑露得甚是碜人。 
<br>
<br>     我亲耳听过他在山头岗和地下死人的对唱。山头岗是我们那儿的乱葬岗，野坟多的山头一般都长满茅草和低矮灌木，牛在这种地方有草食，更可借助灌木驱蚊蝇蹭痒。应古撑了把铁骨锈黑的破伞，身上背着一个稻草结成的蒲团，在满是土包的灌木中游离。起初他是站着唱，远远的看就只有一顶黑色的圆弧罩在灰褐的枝叶中：喂�健�―带来一盔白水酒，想吃来吃唔要走，三伯公你是泥里住，夜里出来逛逛咻，木头（棺材）结坎层层堆，背压背来骨交骨……唱得有些累了，他在光秃的地上坐着草蒲团，一只手扇着光头，一边低着头用不同音调的打呜呼，象是在召集坟墓里面的人：瘸老汉你在哪条路？黄泥黄沙白骨枯。瘸老汉你晓唔晓得回家顾？�邮��咏畔肜��悠�呼……他躺在一座水泥混凝土修茸一新的坟上唱着唱着就睡着了，草蒲团当枕头，手软软的瘫开，忽溜一阵风把他的破伞吹得翻着跟头栽入灌木丛……后来又有一句当地民谚：应古上山头岗，活人（由）死人扛。而教训儿女对吃的独贪则进化为：象你这般毒食，和应古到山头岗唱歌去哦！ 
<br>
<br>     农村应用于教育儿女的援证并不止于应古，只要是较为特殊的人物，都可以作为佐证，比如打屠的老八古的凶神恶煞可以作为吓唬用的招牌，虽孔武有力却愚笨以至于四十多岁仍娶不上媳妇的四蛮，小时因偷窃被老爹一砚掷中后脑勺而留下绰号的吐血鬼……人们以耻笑他们为乐，而他们所表露出来的窘迫和长久以来的忍气吞声更是促进了活跃气氛；有怒气的人一般人家第一次寒碜他，他便会让别人知趣而不敢再作难。应古们面对汹涌的人群的嘲弄，只能是忍耐。他们是一些极不起眼，却又让众人尤其是小孩子印象深刻的人，他们会比较固定的出现在一些地方，比如闪在麻将桌后的某个角落，或清晨携着畚箕在路边夹野粪。偶然有一天，打扑克时有人冒出一句某某死了，众人会有很平常的一句重复：哦？他死了？死得正常便没有延续，比不上洗牌时对手气的评述。 
<br>
<br>     应古死的时候，庸凤嬷、儿子、媳妇照例狠狠的哭了一场，尤其是儿子，身上重孝哭得要别人扶持才站得起来，在三岔路口谢亲的孙子却只跪了几分钟便捱不住，跑玩去了。灵柩上山时路过邻村乌嬷的屋前，需拆了篱笆才能通过，乌嬷持砍刀拦截，并在众目睽睽之下灵巧的劈断了几十年历史的龙索，应古灵柩落地，引发了两族之间一场械斗，互伤了几人，流血不少，最后闹到乡干部前来协调。族里面为引发同情心，长辈们在乡干部到来时，特大摆排场，三牲祭祀，叩拜被惊动的应古公亡魂，这大概是应古享受到的最高待遇。', '我认识的,或者是记忆中的这名老人叫应古。古为音译，指代为雄性，如公牛称为牛古；相对应的雌性称嬷，同样人畜共享，母鸡叫鸡嬷，母猪叫猪嬷，以此类推；女性则如天秀嬷银真嬷等。古与嬷的不同在于，男性的古之前一般只是用名中的最后一字，如福生叫生古、玉应叫应古，而女性则全名加后缀嬷，如应古的老婆叫庸凤嬷，为什么有这个区别，没有人知道；太多的文明已被时光的流沙淹没了。

